create extension if not exists pg_trgm;

-- =====================================================
-- 1. Tabellen
-- =====================================================

create table if not exists public.architecture_relations (
  id uuid primary key default gen_random_uuid(),
  organization_id uuid not null,
  mora_relation_id text not null,
  relation_type text,
  relation_name text,
  documentation text,
  source_mora_element_id text,
  target_mora_element_id text,
  source_name text,
  target_name text,
  source_type text,
  target_type text,
  specialization text,
  created_at timestamptz default now(),
  unique (organization_id, mora_relation_id)
);

create table if not exists public.architecture_domains (
  id uuid primary key default gen_random_uuid(),
  organization_id uuid not null,
  component_id uuid references public.mora_application_components(id) on delete cascade,
  domain_name text not null,
  confidence_score numeric default 70,
  classification_source text default 'auto_keyword',
  created_at timestamptz default now(),
  unique (organization_id, component_id, domain_name)
);

alter table public.architecture_relations enable row level security;
alter table public.architecture_domains enable row level security;

drop policy if exists "architecture_relations_select_org" on public.architecture_relations;
drop policy if exists "architecture_domains_select_org" on public.architecture_domains;
drop policy if exists "architecture_domains_write_org" on public.architecture_domains;

create policy "architecture_relations_select_org"
on public.architecture_relations
for select
using (
  organization_id = (
    select organization_id from public.profiles where id = auth.uid()
  )
);

create policy "architecture_domains_select_org"
on public.architecture_domains
for select
using (
  organization_id = (
    select organization_id from public.profiles where id = auth.uid()
  )
);

create policy "architecture_domains_write_org"
on public.architecture_domains
for all
using (
  organization_id = (
    select organization_id from public.profiles where id = auth.uid()
  )
)
with check (
  organization_id = (
    select organization_id from public.profiles where id = auth.uid()
  )
);

