-- =====================================================
-- 3. Automatische domeinclassificatie
-- =====================================================

-- Eerst oude automatische classificaties verwijderen, handmatige classificaties blijven staan.
delete from public.architecture_domains
where organization_id = '7ec54263-6b9b-4cb2-9b97-526d8909550d'::uuid
  and classification_source = 'auto_keyword';

select
  c.organization_id,
  c.id,
  case
    when txt ~ '(canvas|itslearning|lms|corporate lms|leeromgeving|moodle)' then 'LMS / Digitale leeromgeving'
    when txt ~ '(eduarte|student|studentadministratie|self service eduarte)' then 'Studentadministratie'
    when txt ~ '(xedule|rooster|planning)' then 'Roostering & planning'
    when txt ~ '(afas hr|recruitee|hr|personeel|recruit)' then 'HR'
    when txt ~ '(afas fin|finance|financ|factuur|boekhoud)' then 'Finance'
    when txt ~ '(azure ad|active directory|entra|iam|tools4ever|account portal|identity|identiteit|sso|cards online|cardsonline)' then 'IAM / Identiteit & toegang'
    when txt ~ '(sharepoint|teams|microsoft 365|office 365|onedrive|exchange|mail|outlook)' then 'Samenwerking & communicatie'
    when txt ~ '(portalplus|portal plus|ctrl|api|integratie|middleware|koppeling|portal apps4you|extern portaal)' then 'Integratie & portalen'
    when txt ~ '(topdesk|servicedesk|itsm|esm)' then 'Servicemanagement'
    when txt ~ '(toa|remindo|toets|examen|turnitin|plagiaat)' then 'Toetsing & examinering'
    when txt ~ '(security|siem|defender|firewall|vulnerability|logging|audit)' then 'Security'
    when txt ~ '(decos|join|document|zaak|archief)' then 'Documenten & zaakgericht werken'
    when txt ~ '(qlik|rapport|analytics|bi|dashboard)' then 'Analytics & rapportage'
    else 'Overig / nog te beoordelen'
  end as domain_name,
  case
    when txt ~ '(canvas|eduarte|xedule|afas|azure ad|active directory|tools4ever|sharepoint|topdesk|toa|portalplus|portal plus|recruitee|cardsonline|cards online)' then 90
    when txt ~ '(lms|student|rooster|hr|finance|iam|teams|microsoft|exchange|api|integratie|security|document|analytics)' then 75
    else 45
  end as confidence_score,
  'auto_keyword' as classification_source
from (
  select
    c.*,
    lower(coalesce(c.name,'') || ' ' || coalesce(c.documentation,'') || ' ' || coalesce(c.mora_type,'') || ' ' || coalesce(c.specialization,'')) as txt
  from public.mora_application_components c
  where c.organization_id = '7ec54263-6b9b-4cb2-9b97-526d8909550d'::uuid
) c
on conflict (organization_id, component_id, domain_name) do update set
  confidence_score = excluded.confidence_score,
  classification_source = excluded.classification_source;

-- =====================================================
-- 4. Views
-- =====================================================

create or replace view public.v_architecture_components_with_domain as
select
  c.id,
  c.organization_id,
  c.mora_element_id,
  c.name,
  c.documentation,
  c.specialization,
  c.mora_type,
  d.domain_name,
  d.confidence_score,
  d.classification_source,
  b.beschikbaarheid,
  b.integriteit,
  b.vertrouwelijkheid
from public.mora_application_components c
left join public.architecture_domains d
  on d.organization_id = c.organization_id
 and d.component_id = c.id
left join public.v_mora_application_components_with_biv b
  on b.organization_id = c.organization_id
 and b.id = c.id;

create or replace view public.v_architecture_domain_overview as
select
  organization_id,
  coalesce(domain_name, 'Overig / nog te beoordelen') as domain_name,
  count(*)::integer as component_count,
  round(avg(coalesce(confidence_score, 0))::numeric, 1) as avg_confidence
from public.v_architecture_components_with_domain
group by organization_id, coalesce(domain_name, 'Overig / nog te beoordelen');

create or replace view public.v_architecture_relations_resolved as
select
  id,
  organization_id,
  mora_relation_id,
  relation_type,
  relation_name,
  documentation,
  source_mora_element_id,
  target_mora_element_id,
  source_name,
  target_name,
  source_type,
  target_type,
  specialization,
  created_at
from public.architecture_relations;

create or replace view public.v_architecture_relation_type_summary as
select
  organization_id,
  coalesce(relation_type, 'Onbekend') as relation_type,
  count(*)::integer as relation_count
from public.architecture_relations
group by organization_id, coalesce(relation_type, 'Onbekend');

create or replace view public.v_architecture_shadow_components as
select
  c.*
from public.v_architecture_components_with_domain c
left join public.mora_application_component_matches m
  on m.organization_id = c.organization_id
 and m.mora_component_id = c.id
 and m.match_status in ('confirmed','candidate')
where m.id is null;

